       @TableField("update_time") private LocalDateTime updateTime;
   }
   ```

   TemplateField.java (NEW - Step 2):
   ```java
   @TableName("template_field")
   public class TemplateField {
       @TableId(type = IdType.AUTO) private Long id;
       @TableField("template_id") private Long templateId;
       @TableField("field_name") private String fieldName;
       @TableField("field_label") private String fieldLabel;
       @TableField("field_type") private String fieldType; // TEXT|DATE|SELECT|TEXTAREA|NUMBER
       @TableField("required") private Boolean required;
       @TableField("sort_order") private Integer sortOrder;
       @TableField("options") private String options;
       @TableField("create_time") private LocalDateTime createTime;
   }
   ```

