1	package com.smartoa.service;
2	
3	import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
4	import com.smartoa.dto.LeaveSubmitDTO;
5	import com.smartoa.entity.ApprovalNode;
6	import com.smartoa.entity.ApprovalRecord;
7	import com.smartoa.entity.LeaveRequest;
8	import com.smartoa.entity.User;
9	import com.smartoa.mapper.ApprovalNodeMapper;
10	import com.smartoa.mapper.ApprovalRecordMapper;
11	import com.smartoa.mapper.LeaveRequestMapper;
12	import com.smartoa.mapper.UserMapper;
13	import lombok.RequiredArgsConstructor;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.util.List;
18	
19	@Service
20	@RequiredArgsConstructor
21	public class LeaveService {
22	
23	    private final LeaveRequestMapper leaveRequestMapper;
24	    private final ApprovalRecordMapper approvalRecordMapper;
25	    private final ApprovalNodeMapper approvalNodeMapper;
26	    private final UserMapper userMapper;
27	
28	    @Transactional
29	    public LeaveRequest submitLeave(Long applicantId, LeaveSubmitDTO dto) {
30	        User applicant = userMapper.selectById(applicantId);
31	        if (applicant == null) {
32	            throw new RuntimeException("用户不存在");
33	        }
34	
35	        LeaveRequest request = new LeaveRequest();
36	        request.setApplicantId(applicantId);
37	        request.setTemplateId(dto.getTemplateId());
38	        request.setLeaveType(dto.getLeaveType());
39	        request.setStartDate(dto.getStartDate());
40	        request.setEndDate(dto.getEndDate());
41	        request.setReason(dto.getReason());
42	        request.setStatus("PENDING");
43	        request.setApprovalStep(0);
44	        leaveRequestMapper.insert(request);
45	
46	        // 动态读取模板的审批节点，找到第一个节点并解析审批人
47	        advanceToNextNode(request, applicant);
48	        return request;
49	    }
50	
51	    @Transactional
52	    public void approveLeave(Long requestId, Long approverId, String action, String comment) {
53	        LeaveRequest request = leaveRequestMapper.selectById(requestId);
54	        if (request == null) {
55	            throw new RuntimeException("请假单不存在");
56	        }
57	        if (!"PENDING".equals(request.getStatus())) {
58	            throw new RuntimeException("该请假单已处理");
59	        }
60	        if (!approverId.equals(request.getCurrentApproverId())) {
61	            throw new RuntimeException("您不是当前审批人");
62	        }
63	
64	        int currentStep = request.getApprovalStep();
65	
66	        ApprovalRecord record = new ApprovalRecord();
67	        record.setLeaveRequestId(requestId);
68	        record.setApproverId(approverId);
69	        record.setAction(action);
70	        record.setComment(comment);
71	        record.setApprovalStep(currentStep);
72	        record.setNodeId(request.getCurrentNodeId());
73	        approvalRecordMapper.insert(record);
74	
75	        if ("REJECT".equals(action)) {
76	            request.setStatus("REJECTED");
77	            request.setCurrentApproverId(null);
78	            request.setCurrentNodeId(null);
79	            leaveRequestMapper.updateById(request);
80	            return;
81	        }
82	
83	        // 动态找下一节点
84	        request.setApprovalStep(currentStep + 1);
85	        User applicant = userMapper.selectById(request.getApplicantId());
86	        boolean hasNext = advanceToNextNode(request, applicant);
87	
88	        if (!hasNext) {
89	            request.setStatus("APPROVED");
90	            request.setCurrentApproverId(null);
91	            request.setCurrentNodeId(null);
92	        }
93	        leaveRequestMapper.updateById(request);
94	    }
95	
96	    /**
97	     * 查找当前节点的下一个顺序节点并解析审批人。
98	     * 返回 true 表示找到下一节点，false 表示审批流程结束。
99	     */
100	    private boolean advanceToNextNode(LeaveRequest request, User applicant) {
101	        Long currentNodeId = request.getCurrentNodeId();
102	        Long templateId = request.getTemplateId();
103	
104	        List<ApprovalNode> nodes = approvalNodeMapper.selectList(
105	                new LambdaQueryWrapper<ApprovalNode>()
106	                        .eq(ApprovalNode::getTemplateId, templateId)
107	                        .orderByAsc(ApprovalNode::getSortOrder));
108	
109	        if (nodes.isEmpty()) {
110	            return false;
111	        }
112	
113	        ApprovalNode nextNode;
114	        if (currentNodeId == null) {
115	            // 刚提交，取第一个节点
116	            nextNode = nodes.get(0);
117	        } else {
118	            // 找当前节点之后的节点
119	            int currentIndex = -1;
120	            for (int i = 0; i < nodes.size(); i++) {
121	                if (nodes.get(i).getId().equals(currentNodeId)) {
122	                    currentIndex = i;
123	                    break;
124	                }
125	            }
126	            if (currentIndex < 0 || currentIndex >= nodes.size() - 1) {
127	                return false; // 没有下一节点了
128	            }
129	            nextNode = nodes.get(currentIndex + 1);
130	        }
131	
132	        Long nextApproverId = resolveApprover(nextNode, applicant);
133	        request.setCurrentNodeId(nextNode.getId());
134	        request.setCurrentApproverId(nextApproverId);
135	        return true;
136	    }
137	
138	    /**
139	     * 根据节点配置解析实际的审批人 ID。
140	     */
141	    private Long resolveApprover(ApprovalNode node, User applicant) {
142	        return switch (node.getApproverType()) {
143	            case "DIRECT_LEADER" -> applicant.getDirectLeaderId();
144	            case "DEPARTMENT_HEAD" -> applicant.getDepartmentHeadId();
145	            case "SPECIFIC_USER" -> node.getApproverId();
146	            default -> throw new RuntimeException("不支持的审批人类型: " + node.getApproverType());
147	        };
148	    }
149	
150	    // ========== 撤回 ==========
151	
152	    @Transactional
153	    public void withdrawLeave(Long requestId, Long applicantId) {
154	        LeaveRequest request = leaveRequestMapper.selectById(requestId);
155	        if (request == null) {
156	            throw new RuntimeException("请假单不存在");
157	        }
158	        if (!"PENDING".equals(request.getStatus())) {
159	            throw new RuntimeException("只能撤回审批中的申请");
160	        }
161	        if (!applicantId.equals(request.getApplicantId())) {
162	            throw new RuntimeException("只能撤回自己的申请");
163	        }
164	
165	        ApprovalRecord record = new ApprovalRecord();
166	        record.setLeaveRequestId(requestId);
167	        record.setApproverId(applicantId);
168	        record.setAction("WITHDRAW");
169	        record.setApprovalStep(request.getApprovalStep());
170	        record.setNodeId(request.getCurrentNodeId());
171	        approvalRecordMapper.insert(record);
172	
173	        request.setStatus("WITHDRAWN");
174	        request.setCurrentApproverId(null);
175	        request.setCurrentNodeId(null);
176	        leaveRequestMapper.updateById(request);
177	    }
178	
179	    // ========== 转派 ==========
180	
181	    @Transactional
182	    public void transferLeave(Long requestId, Long currentApproverId, Long toUserId) {
183	        LeaveRequest request = leaveRequestMapper.selectById(requestId);
184	        if (request == null) {
185	            throw new RuntimeException("请假单不存在");
186	        }
187	        if (!"PENDING".equals(request.getStatus())) {
188	            throw new RuntimeException("只能转派审批中的申请");
189	        }
190	        if (!currentApproverId.equals(request.getCurrentApproverId())) {
191	            throw new RuntimeException("您不是当前审批人，无法转派");
192	        }
193	
194	        User target = userMapper.selectById(toUserId);
195	        if (target == null) {
196	            throw new RuntimeException("目标用户不存在");
197	        }
198	
199	        ApprovalRecord record = new ApprovalRecord();
200	        record.setLeaveRequestId(requestId);
201	        record.setApproverId(currentApproverId);
202	        record.setAction("TRANSFER");
203	        record.setComment("转派给 " + target.getRealName());
204	        record.setApprovalStep(request.getApprovalStep());
205	        record.setNodeId(request.getCurrentNodeId());
206	        approvalRecordMapper.insert(record);
207	
208	        request.setCurrentApproverId(toUserId);
209	        leaveRequestMapper.updateById(request);
210	    }
211	
212	    // ========== 查询 ==========
213	
214	    public List<LeaveRequest> getMyRequests(Long applicantId) {
215	        return leaveRequestMapper.selectList(new LambdaQueryWrapper<LeaveRequest>()
216	                .eq(LeaveRequest::getApplicantId, applicantId)
217	                .orderByDesc(LeaveRequest::getCreateTime));
218	    }
219	
220	    public List<LeaveRequest> getPendingRequests(Long approverId) {
221	        return leaveRequestMapper.selectList(new LambdaQueryWrapper<LeaveRequest>()
222	                .eq(LeaveRequest::getCurrentApproverId, approverId)
223	                .eq(LeaveRequest::getStatus, "PENDING")
224	                .orderByDesc(LeaveRequest::getCreateTime));
225	    }
226	
227	    public List<LeaveRequest> getDoneRequests(Long approverId) {
228	        return leaveRequestMapper.selectList(new LambdaQueryWrapper<LeaveRequest>()
229	                .eq(LeaveRequest::getCurrentApproverId, approverId)
230	                .ne(LeaveRequest::getStatus, "PENDING")
231	                .orderByDesc(LeaveRequest::getCreateTime));
232	    }
233	
234	    public LeaveRequest getRequestDetail(Long requestId) {
235	        return leaveRequestMapper.selectById(requestId);
236	    }
237	
238	    public List<ApprovalRecord> getApprovalRecords(Long requestId) {
239	        return approvalRecordMapper.selectList(new LambdaQueryWrapper<ApprovalRecord>()
240	                .eq(ApprovalRecord::getLeaveRequestId, requestId)
241	                .orderByAsc(ApprovalRecord::getCreateTime));
242	    }
243	}
